def list_tools() -> int:
    for name in sorted(TOOLS):
        print(name)
    return 0


def run_tool(name: str, argv: list[str]) -> int:
    if name not in TOOLS:
        print(f"Unknown tool: {name}", file=sys.stderr)
        return 2

    tool = TOOLS[name]
    suffix = '.sh' if tool['kind'] == 'bash' else '.py'
    with tempfile.TemporaryDirectory(prefix='autoresearch-tool-') as tmpdir:
        script_path = Path(tmpdir) / (name.replace('/', '__').replace('.', '_') + suffix)
        script_path.write_text(tool['source'])
        if tool['kind'] == 'bash':
            cmd = ['bash', str(script_path), *argv]
        else:
            cmd = [sys.executable, str(script_path), *argv]
        env = os.environ.copy()
        env.setdefault('PYTHONPATH', str(Path.cwd()))
        return subprocess.call(cmd, cwd=Path.cwd(), env=env)


def main() -> int:
    if len(sys.argv) == 1 or sys.argv[1] in {'-h', '--help'}:
        print(__doc__.strip())
        return 0
    if sys.argv[1] == 'list':
        return list_tools()
    if sys.argv[1] == 'run':
        if len(sys.argv) < 3:
            print('Usage: toolbox.py run <tool> [args...]', file=sys.stderr)
            return 2
        return run_tool(sys.argv[2], sys.argv[3:])
    return run_tool(sys.argv[1], sys.argv[2:])


if __name__ == '__main__':
    raise SystemExit(main())
